```class Solution {
public:
    string reversePrefix(string word, char ch) {
        int index = word.find(ch);
        if (index == string::npos) {
            return word;
        }
        string prefix = word.substr(0, index);
        string suffix = word.substr(index + 1);
        return prefix + suffix;
    }
};
